import java.io.*;
import java.util.*;
import java.math.BigInteger;

public class Main {
    private static long binom(long n, long r) {
        if (r < 0 || r > n) return 0L;
        if (r == 0 || r == n) return 1L;
        if (r > n - r) r = n - r; // use symmetry
        BigInteger result = BigInteger.ONE;
        for (long i = 1; i <= r; i++) {
            result = result.multiply(BigInteger.valueOf(n - r + i));
            result = result.divide(BigInteger.valueOf(i));
        }
        return result.longValue(); // truncates to 64‑bit signed (wraps on overflow)
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        for (int t = 0; t < T; t++) {
            // read next non‑empty line
            while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
            if (line == null) break;
            StringTokenizer st = new StringTokenizer(line);
            long n = Long.parseLong(st.nextToken());
            long k = Long.parseLong(st.nextToken());
            if (k > n) {
                sb.append(0).append('\n');
            } else {
                sb.append(binom(n - 1, k - 1)).append('\n');
            }
        }
        System.out.print(sb.toString());
    }
}

